mapper.sql:
SELECT /* RcpSelfSocFailMapper.getRcpSelfSocFailDtl */ A.PRCS_MDL_IND ,A.EVENT_CODE ,A.SYS_DT ,TO_CHAR(A.SEQ) AS SEQ ,A.NCN AS SVC_CNTR_NO ,A.TRTM_RSLT_SMST ,A.T_SOC_CODE ,A.RSLT_CD AS SUCC_YN ,DECODE(A.RSLT_CD , '0000' , '성공' , '실패') AS SUCC_YN_NM ,DECODE(A.RSLT_CD , '0000' , '' , PRCS_SBST) AS FAIL_RS_NM ,(SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.A_SOC_CODE) AS A_SOC_NM ,(SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.T_SOC_CODE) AS T_SOC_NM ,TO_CHAR(A.SYS_RDATE, 'YYYYMMDDHH24MISS') AS SYS_RDATE ,A.PROC_ID ,F_GET_ADMIN_NM(A.PROC_ID) AS PROC_NM
,TO_CHAR(A.RTY_SEQ) AS RTY_SEQ ,A.TB_NM
FROM ( SELECT PRCS_MDL_IND ,EVENT_CODE ,SYS_DT ,SEQ ,NCN ,TRTM_RSLT_SMST ,RSLT_CD ,PRCS_SBST ,A_SOC_CODE ,T_SOC_CODE ,SYS_RDATE ,'DTL' AS TB_NM ,0 AS RTY_SEQ ,'' AS PROC_ID FROM MCP_SERVICE_ALTER_TRACE@DL_MCP A WHERE PRCS_MDL_IND = #{prcsMdlInd} AND NCN = #{contractNum} AND EVENT_CODE != 'FIN'
AND T_SOC_CODE = #{tSocCd}
UNION ALL SELECT PRCS_MDL_IND ,'X21' AS EVENT_CODE ,TRC_SYS_DT AS SYS_DT ,TRC_SEQ AS SEQ ,NCN ,'부가서비스 재처리' AS TRTM_RSLT_SMST ,RSLT_CD ,PRCS_SBST ,'' AS A_SOC_CODE ,SOC AS T_SOC_CODE ,PROC_DTTM AS SYS_RDATE ,'RTY' AS TB_NM ,SEQ AS RTY_SEQ ,PROC_ID FROM MSP_SOCFAIL_PROC_RTY WHERE PRCS_MDL_IND = #{prcsMdlInd} AND NCN = #{contractNum}
AND SOC = #{tSocCd}
)A ORDER BY SYS_RDATE DESC

mapper.select:
SELECT /* RcpSelfSocFailMapper.getRcpSelfSocFailList */ A.PRCS_MDL_IND as prcsMdlInd, TO_CHAR(A.SYS_RDATE, 'YYYYMMDDHH24MISS') AS sysRdate , (SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.A_SOC_CODE) AS aSocNm, (SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.T_SOC_CODE) AS tSocNm, A.CONTRACT_NUM as contractNum, (SELECT SUB_LINK_NAME FROM MSP_JUO_SUB_INFO WHERE CONTRACT_NUM = A.CONTRACT_NUM) AS custNm, A.PROC_YN as procYn, DECODE(A.PROC_DATE , NULL , '' , TO_CHAR(A.PROC_DATE, 'YYYYMMDDHH24MISS')) AS procDate, A.PROC_ID as procId, A.PROC_MEMO as procMemo, A.SUCC_YN AS succYn, NVL((SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP9033' AND CD_VAL = A.SUCC_YN) , '실패' ) AS succNm, (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP9034' AND CD_VAL = A.CHG_TYPE) AS chgTypeNm FROM MSP_SOCFAIL_PROC_MST A WHERE TO_CHAR(SYS_RDATE , 'YYYYMMDD' ) BETWEEN #{strDate} AND #{endDate}
AND A.CONTRACT_NUM = #{contractNum}
AND A.PROC_YN = #{procYn}
AND A.PROC_YN IS NULL
AND (A.SUCC_YN = #{succYn} OR SUCC_YN IS NULL)
AND A.SUCC_YN = #{succYn}
ORDER BY SYS_RDATE DESC

mapper.update:
UPDATE MSP_SOCFAIL_PROC_MST
SET PROC_YN = #{procYn, jdbcType=VARCHAR}
, PROC_ID = #{procId, jdbcType=VARCHAR}
, PROC_DATE = SYSDATE
, PROC_MEMO = #{procMemo, jdbcType=VARCHAR}
WHERE PRCS_MDL_IND = #{prcsMdlInd, jdbcType=VARCHAR}
AND CONTRACT_NUM = #{contractNum, jdbcType=VARCHAR}

mapper.select:
SELECT /* RcpSelfSocFailMapper.getRcpSelfSocFailListExcel */ A.PRCS_MDL_IND as prcsMdlInd, TO_CHAR(A.SYS_RDATE, 'YYYY-MM-DD HH24:MI:SS') AS sysRdate, (SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.A_SOC_CODE) AS aSocNm, (SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = A.T_SOC_CODE) AS tSocNm, A.CONTRACT_NUM as contractNum, (SELECT SUB_LINK_NAME FROM MSP_JUO_SUB_INFO WHERE CONTRACT_NUM = A.CONTRACT_NUM) AS custNm, A.PROC_YN as procYn, DECODE(A.PROC_DATE , NULL , '' , TO_CHAR(A.PROC_DATE, 'YYYYMMDDHH24MISS')) AS procDate, A.PROC_ID as procId, A.PROC_MEMO as procMemo, NVL((SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP9033' AND CD_VAL = A.SUCC_YN) , '실패' ) AS succYn, B.SUBSCRIBER_NO AS ctn , CASE WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(B.USER_SSN), '-', ''), 7, 1) IN ('1' , '3' , '5' , '7') THEN '남자' WHEN SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(B.USER_SSN), '-', ''), 7, 1) IN ('2' , '4' , '6' , '8') THEN '여자' END gender, TO_CHAR(TO_DATE(B.LST_COM_ACTV_DATE, 'YYYYMMDD' ), 'YYYY-MM-DD') AS lstComActvDate, FN_GET_AGE_JAVA(CRYPTO_AES256.DEC_AES(B.USER_SSN)) AS age, (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = B.OPEN_AGNT_CD AND ROWNUM = 1) AS openAgntNm, FN_GET_CODENM('RCP0007', C.ON_OFF_TYPE) AS onOffType, FN_GET_ORGNM(D.ORGN_ID) AS fstUsimOrgNm, A.A_SOC_AMNT AS aSocAmnt, A.T_SOC_AMNT AS tSocAmnt, (CASE WHEN A.SUCC_YN = 'N' THEN E.PRCS_SBST WHEN A.SUCC_YN IS NULL THEN E.PRCS_SBST ELSE '' END) AS prcsSbst, (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP9034' AND CD_VAL = A.CHG_TYPE) AS chgTypeNm FROM MSP_SOCFAIL_PROC_MST A , MSP_JUO_SUB_INFO B , MSP_REQUEST_DTL C , MSP_PARTNER_USIM_MST D , (SELECT NCN , PRCS_MDL_IND , TRTM_RSLT_SMST, PRCS_SBST, RSLT_CD FROM MCP_SERVICE_ALTER_TRACE@DL_MCP WHERE RSLT_CD != '0000' AND EVENT_CODE != 'FIN') E WHERE A.CONTRACT_NUM = B.CONTRACT_NUM(+) AND A.CONTRACT_NUM = C.CONTRACT_NUM(+) AND C.FST_USIM_NO = D.USIM_NO(+) AND A.PRCS_MDL_IND = E.PRCS_MDL_IND(+) AND A.CONTRACT_NUM = E.NCN(+) AND TO_CHAR(A.SYS_RDATE , 'YYYYMMDD' ) BETWEEN #{strDate} AND #{endDate}
AND A.CONTRACT_NUM = #{contractNum}
AND A.PROC_YN = #{procYn}
AND A.PROC_YN IS NULL
AND (A.SUCC_YN = #{succYn} OR SUCC_YN IS NULL)
AND A.SUCC_YN = #{succYn}
ORDER BY A.SYS_RDATE DESC

mapper.insert:
/* StatsMgmtMapper.insertRtySocFail */
INSERT INTO MSP_SOCFAIL_PROC_RTY(
		 RTY_SEQ
		,SEQ
		,TRC_SEQ
		,TRC_SYS_DT
		,PRCS_MDL_IND
		,CONTRACT_NUM
		,NCN
		,GLOBAL_NO
		,SOC
		,RSLT_CD
		,PRCS_SBST
		,ACCESS_IP
		,PROC_ID
		,PROC_DTTM
)VALUES(
		#{rtySeq}
	   ,(SELECT NVL(MAX(SEQ), 0)+1 FROM MSP_SOCFAIL_PROC_RTY WHERE RTY_SEQ = #{rtySeq})
	   ,#{seq}
	   ,#{sysDt}
	   ,#{prcsMdlInd}
	   ,#{contractNum}
	   ,#{ncn}
	   ,#{globalNo}
	   ,#{tSocCd}
	   ,#{rsltCd}
	   ,#{prcsSbst}
	   ,#{accessIp}
	   ,#{userId}
	   ,SYSDATE
	   )
